async function handleReset(o){o.preventDefault();const r=o.target,n=r.querySelector('button[type="submit"]');n.disabled=!0;const e=new URLSearchParams;e.append("token",document.getElementById("reset_token").value),e.append("password",document.getElementById("password_field").value),e.append("confirm_password",document.getElementById("confirm_password_field").value);try{const t=await fetch("/api/v1/reset-password",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:e}),a=await t.text();t.ok?(await Swal.fire({title:"\xC9xito",text:a,icon:"success",confirmButtonColor:"#4f46e5"}),r.reset(),window.location.href="/admin/login"):Swal.fire({title:"Error",text:a,icon:"error",confirmButtonColor:"#4f46e5"})}catch{Swal.fire({title:"Error de conexi\xF3n",text:"No se pudo conectar con el servidor",icon:"error",confirmButtonColor:"#4f46e5"})}finally{n.disabled=!1}}
